package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.bruto.BerekenSupplementen;
import be.schaubroeck.lpb.rkm.rekenmotor.bruto.BerekenVergoedingen;
import be.schaubroeck.lpb.rkm.rekenmotor.bruto.FlexiJobs;
import be.schaubroeck.lpb.rkm.rekenmotor.bruto.FlexiJobsUtil;
import be.schaubroeck.lpb.rkm.rekenmotor.check.CheckRegimeLoonElementen;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.NlpGlobalService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.ConstantManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManagerImp;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;
import lombok.extern.slf4j.Slf4j;

import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBrutoKey.BRUTO_MAANDLOON_KEY;

@Slf4j
public class BerekenBrutoLoon extends AbstractRekenCommand {

    private static final int SCALE = 2;

    private final LoonElementVerwerker loonElementVerwerker;
    private final CheckRegimeLoonElementen checkRegimeLoonElementen;
    private final FlexiJobs flexiJobs;
    private final BerekenVergoedingen berekenVergoedingen;
    private final BerekenSupplementen berekenSupplementen;

    public BerekenBrutoLoon(ConstantManager constantManager, NlpGlobalService service) {
        this.loonElementVerwerker = new LoonElementVerwerker(constantManager, service.getRszConstantService());
        this.checkRegimeLoonElementen = new CheckRegimeLoonElementen();
        this.flexiJobs = FlexiJobs.builder()
                .aardKodeExtensieFacade(service.getAardKodeExtensieFacade())
                .loonElementVerwerker(loonElementVerwerker)
                .constantManager(constantManager)
                .schaalVerhogingService(service.getSchaalVerhogingService())
                .schaalVersieService(service.getSchaalVersieService())
                .flexiJobsUtil(new FlexiJobsUtil(constantManager))
                .build();
        LoonElementVerwerker loonElementVerwerker = new LoonElementVerwerker(constantManager, service.getRszConstantService());
        this.berekenVergoedingen = new BerekenVergoedingen(constantManager, service, loonElementVerwerker);

        this.berekenSupplementen = new BerekenSupplementen(service, constantManager, loonElementVerwerker);
    }

    @Override
    protected boolean execute(RekenContext mainContext) {
        mainContext.put(RekenChainKey.LOONELEMENT_MANAGER_KEY, new LoonElementManagerImp());
        Persoon persoon = mainContext.getUnchecked(RekenChainKey.PERSOON_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            berekenBrutoLoon(opdrachtContext, opdracht);
            checkRegimeLoonElementen.check(mainContext, opdracht);
        }
        return CONTINUE_PROCESSING;
    }

    private void berekenBrutoLoon(RekenContext context, Opdracht opdracht) {
        berekenVergoedingen.bereken(context, opdracht);
        berekenSupplementen.bereken(context, opdracht);
        flexiJobs.doeControles(context, opdracht);
        flexiJobs.vormVakantieGeld(context, opdracht);

        LoonElementManager manager = context.getLoonElementManager();
        Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);
        log.debug("{} {}", opdracht.getOpdrachtnr(), loonElementen);

        Money brutoMaandLoon = RekenTools.getSomProperty(BRUTO_MAANDLOON_KEY, loonElementen);
        context.put(BRUTO_MAANDLOON_KEY, brutoMaandLoon.round(SCALE));
    }


}
